type CDC_Line_Coding is record
   Bitrate   : UInt32;
   Stop_Bit  : UInt8;
   Parity    : UInt8;
   Data_Bits : UInt8;
end record;

type CDC_Line_Control_State is record
   DTE_Is_Present   : Boolean;
   Half_Duplex_Carrier_control : Boolean;
   Reserved : UInt14;
end record;

